use std::collections::HashMap;

fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let total_sum: i64 = nums.iter().sum();
    let mut prefix_sum = 0;
    let mut mod_map = HashMap::new();
    mod_map.insert(0, 0);
    let mut dp_prev = 0;
    for num in nums {
        prefix_sum += num;
        let mod_val = prefix_sum % k;
        let candidate: i64 = if mod_map.contains_key(&mod_val) {
            mod_map[&mod_val] + prefix_sum
        } else {
            0
        };
        let current_dp = std::cmp::max(dp_prev, candidate);
        let current_val = current_dp - prefix_sum;
        if mod_map.contains_key(&mod_val) {
            if current_val > mod_map[&mod_val] {
                mod_map.insert(mod_val, current_val);
            }
        } else {
            mod_map.insert(mod_val, current_val);
        }
        dp_prev = current_dp;
    }
    total_sum - dp_prev
}
