use std::collections::HashMap;

fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let mut dp = vec![0; n + 1];
    let mut remainder_map = HashMap::new();
    remainder_map.insert(0, 0);
    let mut current_prefix_sum = 0;
    for i in 1..=n {
        current_prefix_sum += nums[i - 1];
        let current_remainder = current_prefix_sum % k;
        let candidate = remainder_map.get(&current_remainder).copied().unwrap_or(i64::MAX);
        let dp_i = std::cmp::min(dp[i - 1] + nums[i - 1], candidate);
        dp[i] = dp_i;
        if let Some(existing) = remainder_map.get_mut(&current_remainder) {
            if dp_i < *existing {
                *existing = dp_i;
            }
        } else {
            remainder_map.insert(current_remainder, dp_i);
        }
    }
    dp[n]
}
